// Java companion service called from Rails via JRuby
public class SessionValidatorService {
    private final String secretKey;
    private final int expirationSeconds;

    public SessionValidatorService(String secretKey, int expirationSeconds) {
        this.secretKey = secretKey;
        this.expirationSeconds = expirationSeconds;
    }

    public boolean isValid(String token) {
        return JWT.decode(token, secretKey).getExpiration() > System.currentTimeMillis();
    }
}
